CREATE VIEW "public"."view__model_stats_by_device" AS (select "models"."id" as "model_id", "models"."display_name", "models"."format", "models"."parameters", "models"."quant", "models"."architecture", "devices"."id" as "device_id", "devices"."os_name", "devices"."cpu", "devices"."cpu_cores", "devices"."gpu", "devices"."gpu_cores", "devices"."ram_gb", "runs"."runtime_name", count(distinct "runs"."id") as "run_count", count("trials"."id") as "trial_count", PERCENTILE_CONT(0.5) WITHIN GROUP (ORDER BY "trials"."ttft_ms") as "ttft_p50_ms", PERCENTILE_CONT(0.95) WITHIN GROUP (ORDER BY "trials"."ttft_ms") as "ttft_p95_ms", avg("trials"."decode_tps") as "avg_decode_tps", avg("trials"."prefill_tps") as "avg_prefill_tps", avg("trials"."idle_rss_mb") as "avg_idle_rss_mb", avg("trials"."peak_rss_mb") as "avg_peak_rss_mb" from "trials" inner join "runs" on "trials"."run_id" = "runs"."id" inner join "models" on "runs"."model_id" = "models"."id" inner join "devices" on "runs"."device_id" = "devices"."id" group by "models"."id", "devices"."id", "runs"."runtime_name");